@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@notification.Message</span>
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR (and reuse on interactive activation)
        notifications = NotificationService.GetNotifications();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only starts after the component is interactive in the browser
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(5000, cancellationToken);

            // Simulate a new notification arriving on the server
            NotificationService.SimulateIncoming();

            var newItems = NotificationService.GetNotificationsSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

